package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithSkipHeaderRecord_noArg() {
        CSVFormat original = CSVFormat.DEFAULT;
        CSVFormat modified = original.withSkipHeaderRecord();

        assertNotNull(modified);
        assertTrue(modified.getSkipHeaderRecord());
        // Original should be unchanged
        assertFalse(original.getSkipHeaderRecord());
        // Calling withSkipHeaderRecord() should be equivalent to withSkipHeaderRecord(true)
        CSVFormat modifiedExplicit = original.withSkipHeaderRecord(true);
        assertEquals(modified, modifiedExplicit);
    }
}
